    "vip.breakout_left_2_title": "VIP-Eintrittsservice",
    "vip.breakout_left_2_line": "Keine Warteschlange. Persönliche Begrüßung und Vorzugszugang.",
    "vip.breakout_right_1_title": "Zugang zu exklusiven Venues",
