const LANG_STORAGE_KEY = "prestix-lang";

function getStoredLang(): Lang {
  if (typeof window === "undefined") return "en";
  try {
    const s = localStorage.getItem(LANG_STORAGE_KEY);
    if (s && SUPPORTED_LANGS.includes(s as Lang)) return s as Lang;
  } catch {}
  return "en";
}

export function getLang(): Lang {
  return getStoredLang();
}

export function setLang(lang: Lang): void {
  if (typeof window === "undefined") return;
  try {
    localStorage.setItem(LANG_STORAGE_KEY, lang);
  } catch {}
}

export function t(key: string, lang?: Lang): string {
  const l = lang ?? getStoredLang();
  const dict = translations[l] ?? translations.en;
  const fallback = translations.en;
  return dict[key] ?? fallback[key] ?? key;
}

export function getTranslations(lang?: Lang): Record<string, string> {
  const l = lang ?? getStoredLang();
  return { ...translations.en, ...(translations[l] ?? {}) };
}
